questions = [
    {
        "question": "What is 7 x 8?",
        "options": ["54", "56", "58", "64"],
        "answer": 1
    },
    {
        "question": "Which is a Python data type?",
        "options": ["table", "column", "list", "row"],
        "answer": 2
    },
    {
        "question": "What does len([1, 2, 3]) return?",
        "options": ["1", "2", "3", "4"],
        "answer": 2
    }
]

def ask_question(q, number):
    print("Q" + str(number) + ": " + q["question"])
    for i in range(len(q["options"])):
        print("  " + str(i) + ") " + q["options"][i])
    guess = int(input("Your answer (0-3): "))
    if guess == q["answer"]:
        print("Correct!")
        return True
    else:
        correct = q["options"][q["answer"]]
        print("Wrong! Answer was: " + correct)
        return False

score = 0
for i in range(len(questions)):
    if ask_question(questions[i], i + 1):
        score += 1

print("---")
print("Score: " + str(score) + "/" + str(len(questions)))

