    {"question": "Capital of Myanmar?", "options": ["Yangon", "Mandalay", "Naypyidaw", "Bago"], "answer": 2},
    {"question": "2 ** 10 = ?", "options": ["512", "1024", "2048", "256"], "answer": 1},
    {"question": "len(\"hello\") = ?", "options": ["4", "5", "6", "3"], "answer": 1}
]

def get_grade(score, total):
    percent = score / total * 100
    if percent == 100:
        return "Perfect!"
    elif percent >= 67:
        return "Great job!"
    else:
        return "Keep practising!"

random.seed(42)
random.shuffle(questions)

score = 0
for i, q in enumerate(questions):
    print("Q" + str(i + 1) + ": " + q["question"])
    for j, opt in enumerate(q["options"]):
        print("  " + str(j) + ") " + opt)
    guess = q["answer"]   # auto-answer for demo
    if guess == q["answer"]:
        score += 1

print("Score:", score, "/", len(questions))
print(get_grade(score, len(questions)))

